def _parse_action(reply: str) -> tuple[str | None, str | None, str]:
    import re
    stripped = reply.lstrip()
    match = re.match(r"^\[ACTION:([^\]]+)\]\s*", stripped)
    if not match:
        return None, None, reply
    tag_content = match.group(1)
    text_after = reply[match.end():]
    parts = tag_content.split(":", 1)
    action_type = parts[0].strip()
    action_param = parts[1].strip() if len(parts) > 1 else None
    return action_type, action_param, text_after

def run_async_search(last_name: str, city_name: str = None):
    async def _search():
        results = []
        if not VK_TOKEN or "ТВОЙ_" in VK_TOKEN:
            return ["⚠️ На сервере не задан VK_API_TOKEN для глубокого OSINT-анализа."]

        url = "https://api.vk.com/method/users.search"
        params = {
            "q": last_name,
            "count": 15,
            "fields": "bdate,city,connections",
            "access_token": VK_TOKEN,
            "v": "5.131"
        }
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(url, params=params, timeout=8) as response:
                    data = await response.json()
                    if "response" in data:
                        for item in data["response"]["items"]:
                            if city_name:
                                user_city = item.get("city", {}).get("title", "").lower()
                                if city_name.lower() not in user_city:
                                    continue
                            name = f"{item.get('first_name')} {item.get('last_name')}"
                            vk_link = f"https://vk.com/id{item.get('id')}"
                            bdate = item.get("bdate", "не указана")
                            results.append(f"👤 {name}\n📅 ДР: {bdate}\n🔗 Ссылка: {vk_link}")
        except Exception as e:
            return [f"⚠️ Ошибка сети при парсинге OSINT графа: {e}"]
        return results

    try:
        loop = asyncio.get_event_loop()
    except RuntimeError:
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
    return loop.run_until_complete(_search())


